const sponsors = $items("Get sponsors up for reminder");

const calendarItems = $items("Available future events");
const calendar = calendarItems.map(item => item.json);

function normalize(str) {
  return (str || "").toString().trim().toLowerCase();
}

const output = [];

for (const sponsorItem of sponsors) {

  const sponsor = sponsorItem.json;

  const sponsorName = sponsor["Full Name"];
  const sponsorEmail = sponsor["Email Address"];
  const participatingRaw = sponsor["Event Participating In"] || "";

  const participatingEventIds = participatingRaw
    .split(",")
    .map(e => normalize(e))
    .filter(e => e.length > 0);

  const recommendedEvents = calendar
    .filter(event => {

      const eventId = normalize(event["eventId"]);

      return (
        !participatingEventIds.includes(eventId)
      );
    })
    .map(event => event["eventName"]);

  output.push({
    json: {
      sponsorName,
      sponsorEmail,
      recommendedEvents
    }
  });
}

return output;

