// ===============================
// 1. LOAD DATA
// ===============================

const events = $items("Event Calendar1").map(i => i.json);
const sponsors = $items("Sponsor List1").map(i => i.json);

const sponsorData = $('Get Sponsor by Email').first().json;
const webhookData = $('Webhook').first().json.body;
const config = $('Event Config1').first().json;


// ===============================
// 2. HELPERS
// ===============================

function normalize(str) {
  return (str || "").toString().trim().toLowerCase();
}

function strToArray(str) {
  return (str || "")
    .split(",")
    .map(normalize)
    .filter(Boolean);
}

function normalizeDate(d) {
  const date = new Date(d);
  date.setHours(0,0,0,0);
  return date;
}

const today = new Date();
today.setHours(0,0,0,0);


// ===============================
// 3. COUNT CURRENT SPONSORS PER EVENT
// ===============================

const eventCounts = {};

for (const e of events) {
  const eventId = normalize(e["Event ID"]);
  eventCounts[eventId] = 0;

  for (const s of sponsors) {
    const participating = strToArray(s["Event Participating In"]);
    if (participating.includes(eventId)) {
      eventCounts[eventId]++;
    }
  }
}


// ===============================
// 4. PREPARE REQUEST DATA
// ===============================

const existingEventIds = strToArray(
  sponsorData["Event Participating In"]
);

const requestedEventNames = strToArray(
  webhookData.Event
);

const maxSlot = Number(config.sponsor_maxSponsorPerEvent);
const unusedCredit = Number(sponsorData["Unused Credit"]) || 0;


// ===============================
// 5. MAP REQUESTED EVENTS
// ===============================

const mappedEvents = requestedEventNames
  .map(name => {
    const match = events.find(ev =>
      normalize(ev["Event Name"]) === normalize(name)
    );

    if (!match) return null;

    const eventId = normalize(match["Event ID"]);

    return {
      eventId,
      eventName: match["Event Name"],
      eventDate: match["Event Date"],
      sponsorCount: eventCounts[eventId] || 0
    };
  })
  .filter(Boolean);


// ===============================
// 6. RECONCILIATION LOGIC
// ===============================

const acceptedEvents = [];
const rejectedEvents = [];

for (const e of mappedEvents) {

  const eventDate = normalizeDate(e.eventDate);

  // Priority 1: Past event
  if (eventDate < today) {
    rejectedEvents.push({ ...e, reason: "Event date has already passed" });
    continue;
  }

  // Priority 2: Already registered
  if (existingEventIds.includes(e.eventId)) {
    rejectedEvents.push({ ...e, reason: "Already registered for this event" });
    continue;
  }

  // Priority 3: Event full
  if (e.sponsorCount >= maxSlot) {
    rejectedEvents.push({ ...e, reason: "Event is already full" });
    continue;
  }

  acceptedEvents.push(e);
}


// ===============================
// 7. CREDIT VALIDATION
// ===============================

if (acceptedEvents.length > unusedCredit) {

  const allowed = acceptedEvents.slice(0, unusedCredit);
  const excess = acceptedEvents.slice(unusedCredit);

  for (const e of excess) {
    rejectedEvents.push({
      ...e,
      reason: "Insufficient sponsorship credits"
    });
  }

  acceptedEvents.length = 0;
  acceptedEvents.push(...allowed);
}


// ===============================
// 8. CREDIT CALCULATION
// ===============================

const remainingCredit = Math.max(
  0,
  unusedCredit - acceptedEvents.length
);


// ===============================
// 9. EMAIL HTML BUILDERS
// ===============================

const acceptedHtml = acceptedEvents.length
  ? "<ul>" + acceptedEvents.map(e =>
      `<li><strong>${e.eventName}</strong> (${e.eventDate})</li>`
    ).join("") + "</ul>"
  : "No events were accepted.";

const rejectedHtml = rejectedEvents.length
  ? "<ul>" + rejectedEvents.map(e =>
      `<li><strong>${e.eventName}</strong> - ${e.reason}</li>`
    ).join("") + "</ul>"
  : "No events were rejected.";


//
// ===============================
// 10. FINAL OUTPUT (n8n FORMAT)
// ===============================
//

return [
  {
    json: {
      SponsorName: sponsorData["Sponsor Name"],
      AcceptedEvents: acceptedEvents,
      RejectedEvents: rejectedEvents,
      AcceptedHtml: acceptedHtml,
      RejectedHtml: rejectedHtml,
      RequestedEvents: requestedEventNames,
      ExistingEvents: existingEventIds,
      CreditsUsed: acceptedEvents.length,
      NewCredit: remainingCredit
    }
  }
];

