// 1. Get all events
const events = $items("Event Calendar1").map(item => item.json);

// 2. Get all sponsors
const sponsors = $items("Sponsor List1").map(item => item.json);

function normalize(str) {
  return (str || "").toString().trim().toLowerCase();
}

function strToArray(str) {
  return (str || "").split(",").map(normalize).filter(e => e.length > 0);
}

function normalizeDate(d) {
  const date = new Date(d);
  date.setHours(0,0,0,0);
  return date;
}

const today = new Date();
today.setHours(0,0,0,0);

// 3. Calculate sponsor counts for all events
const eventCounts = {};
for (const e of events) {
  const eventId = normalize(e["Event ID"]);
  eventCounts[eventId] = 0;
  for (const s of sponsors) {
    const sEvents = strToArray(s["Event Participating In"]);
    if (sEvents.includes(eventId)) eventCounts[eventId]++;
  }
}

// 4. Get sponsor info from webhook
const existingEventIds = strToArray(
  $('Get Sponsor by Email').first().json['Event Participating In']
);

const newEventNames = strToArray(
  $('Webhook').first().json.body.Event
);

// 5. Map new event names to IDs
const newEventIdMap = newEventNames.map(newEvent => {
  const match = events.find(ev =>
    normalize(ev["Event Name"]) === normalize(newEvent)
  );

  if (match) {
    return {
      eventId: normalize(match["Event ID"]),
      eventName: match["Event Name"],
      eventDate: match["Event Date"],
      sponsorCount: eventCounts[normalize(match["Event ID"])]
    };
  }

  return null;
}).filter(e => e !== null);

// 6. Reconcile
const acceptedEvents = [];
const removedAlreadyRegistered = [];
const removedFull = [];
const removedPastEvent = [];

const maxSlot = Number($('Event Config1').first().json.sponsor_maxSponsorPerEvent);

for (const e of newEventIdMap) {

  const eventDate = normalizeDate(e.eventDate);

  // 🔴 Past event check (FIRST priority)
  if (eventDate < today) {
    removedPastEvent.push(e);

  } else if (existingEventIds.includes(e.eventId)) {
    removedAlreadyRegistered.push(e);

  } else if (e.sponsorCount >= maxSlot) {
    removedFull.push(e);

  } else {
    acceptedEvents.push(e);
  }
}

// Remove Excess Event Base on Available Credit
const RemovedInsufficientCredit = [];

const unusedCredit = $('Get Sponsor by Email').first().json['Unused Credit'];
const creditLimit = Number(unusedCredit) || 0;

// New Credit 
const remainingCredit = Math.max(
  0,
  Number(unusedCredit) - acceptedEvents.length
);

if (acceptedEvents.length > creditLimit) {

  // Keep only up to credit limit
  const allowedEvents = acceptedEvents.slice(0, creditLimit);

  // Everything beyond credit limit is rejected
  const excessEvents = acceptedEvents.slice(creditLimit);

  for (const e of excessEvents) {
    RemovedInsufficientCredit.push(e);
  }

  // Replace acceptedEvents with limited list
  acceptedEvents.length = 0;
  acceptedEvents.push(...allowedEvents);
}

// 7. Output
return {
  AcceptedEvents: acceptedEvents,
  RemovedAlreadyRegistered: removedAlreadyRegistered,
  RemovedFull: removedFull,
  RemovedPastEvent: removedPastEvent,
  ExistingEvents: existingEventIds,
  RequestedEvents: newEventNames,
  NewCredit: remainingCredit,
};
